mapper.select:
SELECT f.fleet_id, f.fleet_name, f.captain_id, f.create_time, d.name AS captain_name FROM fleet f LEFT JOIN driver d ON f.captain_id = d.driver_id
AND f.fleet_name LIKE CONCAT('%', #{fleetName}, '%')
AND f.create_time >= #{startTime}
AND f.create_time <= #{endTime}
ORDER BY f.create_time DESC

mapper.update:
UPDATE fleet
fleet_name = #{fleetName}, captain_id = #{captainId}, create_time = #{createTime},
WHERE fleet_id = #{fleetId}
